const AWS = require('aws-sdk');
const crypto = require('crypto');

const dynamodb = new AWS.DynamoDB.DocumentClient();

const TABLE_NAME = process.env.USERS_TABLE || 'Users';
const EMAIL_INDEX = process.env.EMAIL_INDEX || 'email-index';
const PASSWORD_SALT_BYTES = parseInt(process.env.PASSWORD_SALT_BYTES || '16', 10);
const PASSWORD_ITERATIONS = parseInt(process.env.PASSWORD_ITERATIONS || '100000', 10);
const PASSWORD_KEYLEN = parseInt(process.env.PASSWORD_KEYLEN || '64', 10);
const PASSWORD_DIGEST = process.env.PASSWORD_DIGEST || 'sha512';
const CORS_ORIGIN = process.env.CORS_ORIGIN || '*';

function response(statusCode, body) {
  return {
    statusCode,
    headers: {
      'Content-Type': 'application/json',
      'Access-Control-Allow-Origin': CORS_ORIGIN,
      'Access-Control-Allow-Headers': 'Content-Type,Authorization',
      'Access-Control-Allow-Methods': 'OPTIONS,POST'
    },
    body: JSON.stringify(body)
  };
}

function normalizeEmail(email) {
  return String(email || '').trim().toLowerCase();
}

function validateEmail(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function validatePassword(password) {
  return typeof password === 'string' && password.length >= 8 && password.length <= 128;
}

function hashPassword(password) {
  const salt = crypto.randomBytes(PASSWORD_SALT_BYTES).toString('hex');
  const hash = crypto.pbkdf2Sync(password, salt, PASSWORD_ITERATIONS, PASSWORD_KEYLEN, PASSWORD_DIGEST).toString('hex');
  return {
    salt,
    hash,
    iterations: PASSWORD_ITERATIONS,
    keylen: PASSWORD_KEYLEN,
    digest: PASSWORD_DIGEST
  };
}

async function emailExists(email) {
  const result = await dynamodb.query({
    TableName: TABLE_NAME,
    IndexName: EMAIL_INDEX,
    KeyConditionExpression: 'email = :email',
    ExpressionAttributeValues: {
      ':email': email
    },
    Limit: 1
  }).promise();

  return !!(result.Items && result.Items.length);
}

exports.handler = async (event) => {
  try {
    if (event.httpMethod === 'OPTIONS') {
      return response(200, { ok: true });
    }

    if (event.httpMethod !== 'POST') {
      return response(405, { error: 'Method not allowed' });
    }

    let payload;
    try {
      payload = typeof event.body === 'string' ? JSON.parse(event.body) : event.body || {};
    } catch (_) {
      return response(400, { error: 'Invalid JSON body' });
    }

    const email = normalizeEmail(payload.email);
    const password = payload.password;

    if (!validateEmail(email)) {
      return response(400, { error: 'Invalid email' });
    }

    if (!validatePassword(password)) {
      return response(400, { error: 'Password must be between 8 and 128 characters' });
    }

    const exists = await emailExists(email);
    if (exists) {
      return response(409, { error: 'Account already exists' });
    }

    const passwordData = hashPassword(password);
    const userId = crypto.randomUUID();
    const now = new Date().toISOString();

    const item = {
      userId,
      email,
      passwordHash: passwordData.hash,
      passwordSalt: passwordData.salt,
      passwordIterations: passwordData.iterations,
      passwordKeylen: passwordData.keylen,
      passwordDigest: passwordData.digest,
      createdAt: now,
      updatedAt: now
    };

    await dynamodb.put({
      TableName: TABLE_NAME,
      Item: item,
      ConditionExpression: 'attribute_not_exists(userId)'
    }).promise();

    return response(201, {
      userId,
      email,
      createdAt: now
    });
  } catch (err) {
    console.error('Registration error:', err);
    return response(500, { error: 'Internal server error' });
  }
};